function solve(nums: number[], k: number): number {
    const n = nums.length;
    const prefixXOR = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixXOR[i + 1] = prefixXOR[i] ^ nums[i];
    }

    // Create a 2D array to store the minimum maximum XOR for the first i elements divided into j groups
    const dp = new Array(n + 1).fill(0).map(() => new Array(k + 1).fill(0));

    // Initialize the dp array
    for (let i = 1; i <= n; i++) {
        dp[i][1] = prefixXOR[i];
    }

    for (let j = 2; j <= k; j++) {
        for (let i = j; i <= n; i++) {
            dp[i][j] = Infinity;
            for (let m = j - 1; m < i; m++) {
                const currentMax = Math.max(dp[m][j - 1], prefixXOR[i] ^ prefixXOR[m]);
                if (currentMax < dp[i][j]) {
                    dp[i][j] = currentMax;
                }
            }
        }
    }

    return dp[n][k];
}

